package programming;

public class Swap {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 20;
		int b = 45;
		System.out.println("Before swapping a = " + a + " and b = " + b );
		int temp = a;
		a = b;
		b = temp;
		System.out.println("After swapping a = " + a + " and b = " + b);

	}

}
